insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('f6641647-c9e1-554a-b211-6e711fa6a868','00000000-0000-0000-0000-00000000b004','prive','The Privé','project','Flagship BLUEMARQ 2025–2026 · tiền thân: Gem Riverside','[{"key":"Tên dự án","value":"The Privé"},{"key":"Tên cũ","value":"Gem Riverside (2018)"},{"key":"Chủ đầu tư","value":"BLUEMARQ GROUP (Đất Xanh cũ)"},{"key":"Vị trí","value":"Đường Song Hành CT Long Thành, P. An Phú, TP Thủ Đức (Q2 cũ)"},{"key":"Quy mô đất","value":"~6,7 ha (cần đối chiếu hồ sơ)"},{"key":"Tháp","value":"12 block · 33–34 tầng (cần đối chiếu)"},{"key":"Số căn","value":"~3.175 căn hộ (cần đối chiếu)"},{"key":"Đặc điểm","value":"3 mặt giáp sông Giồng Ông Tố"},{"key":"Bàn giao dự kiến","value":"2027–2028 (chưa khóa)"}]'::jsonb,'"Một tập đoàn vừa đổi tên thương hiệu sau hơn 20 năm sẽ không bao giờ để dự án flagship đầu tiên của tên mới thất bại. Khi Anh/Chị mua The Privé, Anh/Chị đang mua dự án mà chủ đầu tư bắt buộc phải làm bằng được."','The Privé là dự án căn hộ cao tầng ven sông tại phường An Phú, TP Thủ Đức — được BLUEMARQ GROUP (tên mới của Tập đoàn Đất Xanh từ 20/05/2026) xác nhận là dự án flagship tại TP.HCM giai đoạn 2025–2026. Đây chính là sự hồi sinh của Gem Riverside — dự án từng mở bán năm 2018 rồi dừng triển khai nhiều năm vì rà soát pháp lý. Việc tái khởi động chỉ diễn ra sau khi pháp lý được tái lập (~2024), nên câu chuyện bán hàng cốt lõi là: một vị trí ven sông hiếm tại An Phú + một chủ đầu tư đang đặt toàn bộ uy tín thương hiệu mới vào đúng dự án này. Lợi thế vật lý khó sao chép: 3 mặt giáp sông Giồng Ông Tố, sát trục Song Hành cao tốc Long Thành và nút giao An Phú — cửa ngõ hạ tầng lớn nhất khu Đông.',0),
  ('3394647c-fa6f-5687-86cf-e85a738bbf20','00000000-0000-0000-0000-00000000b004','bluemarq','BLUEMARQ GROUP','developer',null,'[{"key":"Tiền thân","value":"Tập đoàn Đất Xanh (DXG)"},{"key":"Công bố rebrand","value":"20/05/2026"},{"key":"GCN ĐKDN tên mới","value":"06/05/2026"},{"key":"Vốn điều lệ","value":">11.141 tỷ đồng"},{"key":"Tổng tài sản hợp nhất","value":">38.100 tỷ đồng"}]'::jsonb,'"BLUEMARQ không phải chủ đầu tư mới — đây là Đất Xanh với hơn 20 năm thị trường, vốn điều lệ hơn 11.000 tỷ, chọn The Privé làm sản phẩm mở màn cho thương hiệu mới."','BLUEMARQ GROUP là tên thương hiệu mới của Tập đoàn Đất Xanh, công bố ngày 20/05/2026 sau khi Đại hội cổ đông thông qua và được cấp giấy chứng nhận đăng ký doanh nghiệp tên mới ngày 06/05/2026. Trong bộ công bố chính thức, doanh nghiệp xác nhận The Privé là dự án flagship tại TP.HCM trong giai đoạn 2025–2026 — gắn trực tiếp với chu kỳ tái định vị thương hiệu.',1),
  ('b6304013-576b-5035-b816-e9dec73c8828','00000000-0000-0000-0000-00000000b004','datxanh','Đất Xanh Group (DXG)','developer',null,'[{"key":"Thành lập","value":"2003, TP.HCM"},{"key":"Niêm yết","value":"HoSE: DXG"},{"key":"Hệ sinh thái","value":"Phát triển BĐS + Dịch vụ (DXS)"},{"key":"Track record","value":"Gem Sky World (92ha Long Thành), Opal Skyline/Boulevard, Luxcity..."},{"key":"Vị thế","value":"Hệ thống phân phối BĐS lớn hàng đầu VN"}]'::jsonb,'"Đất Xanh từng bán hàng cho cả thị trường trước khi tự làm chủ đầu tư — họ hiểu người mua Việt Nam hơn bất kỳ CĐT nào."','Đất Xanh đi lên từ phân phối BĐS rồi trở thành nhà phát triển — thế mạnh độc nhất là vừa làm chủ đầu tư vừa sở hữu lực lượng bán hàng khổng lồ qua Đất Xanh Services. Track record phát triển: Gem Sky World (Long Thành), chuỗi Opal (Bình Dương), Gem Riverside (nay là The Privé). Giai đoạn 2018–2023 tập đoàn chịu áp lực lớn từ việc Gem Riverside đình trệ — và việc hồi sinh được dự án này là cột mốc phục hồi quan trọng nhất của họ.',2),
  ('29259182-2c42-5455-8965-936f32be1fae','00000000-0000-0000-0000-00000000b004','dxs','Đất Xanh Services (DXS)','developer',null,'[{"key":"Vai trò","value":"Tổng đại lý phân phối hệ sinh thái"},{"key":"Niêm yết","value":"HoSE: DXS"},{"key":"Quy mô","value":"Mạng lưới sàn & sale phủ toàn quốc"}]'::jsonb,null,'DXS là cánh tay phân phối của hệ sinh thái — đảm bảo The Privé có lực bán in-house quy mô lớn ngay khi mở bán, không phụ thuộc hoàn toàn đại lý ngoài. Với sales: tốc độ hấp thụ các đợt đầu thường được "bảo chứng" bởi chính hệ thống này — cần theo dõi số liệu thật từng đợt thay vì tin con số truyền thông.',3),
  ('dcd03b83-03fa-5b7f-af8f-4c8e71137865','00000000-0000-0000-0000-00000000b004','flagship','Định vị Flagship 2025–2026','developer',null,'[{"key":"Thông điệp","value":"Ra mắt dự án flagship The Privé tại TP.HCM"},{"key":"Giai đoạn","value":"2025–2026"},{"key":"Ý nghĩa","value":"Sản phẩm mở màn chu kỳ thương hiệu mới"}]'::jsonb,'"Flagship nghĩa là: ngân sách tốt nhất, đội ngũ tốt nhất, và áp lực hoàn thành cao nhất — tất cả dồn vào dự án này."','Trong các công bố chính thức của giai đoạn rebrand, The Privé được nêu đích danh là flagship. Đây là talking point hạng A vì nó được xác nhận từ nguồn chủ đầu tư, không phải tin môi giới.',4),
  ('afe0f3eb-aadb-518e-a533-8a8b57f575cd','00000000-0000-0000-0000-00000000b004','gem-riverside','Gem Riverside (2018)','legal','Tiền thân của The Privé','[{"key":"Công bố","value":"2017–2018"},{"key":"Định vị cũ","value":"Hometel resort ven sông"},{"key":"Booking giai đoạn đầu","value":"~1.000+ căn (cần đối chiếu)"},{"key":"Trạng thái","value":"Dừng triển khai từ 2018–2019"},{"key":"Khách cũ","value":"Được hoàn/chuyển quyền lợi (cần xác minh chính sách cụ thể)"}]'::jsonb,'"Dự án này từng dừng vì pháp lý — và chính vì thế nó là dự án bị soi pháp lý kỹ nhất khu Đông trước khi quay lại. Cái gì đã qua được vòng rà soát đó thì sạch hơn nhiều dự án chưa từng bị kiểm tra."','Gem Riverside là tên gốc của dự án — mở bán rầm rộ năm 2018 với vị trí ven sông Giồng Ông Tố, sau đó dừng triển khai do vướng rà soát pháp lý đất đai. Đây là "lịch sử" mà gần như mọi khách hàng tìm hiểu kỹ đều sẽ hỏi. Nguyên tắc tư vấn: không né, không xóa lịch sử. Chủ động kể đúng trình tự — dừng vì rà soát pháp lý → hoàn thiện nghĩa vụ pháp lý → được cấp lại giấy phép → mới relaunch. Trình tự này biến điểm yếu thành bằng chứng sàng lọc pháp lý.',5),
  ('01f5e2e7-bc24-517e-aa5b-5a9c9a7d5c41','00000000-0000-0000-0000-00000000b004','legal-pause','Giai đoạn rà soát 2018–2023','legal','⚠ Điểm nhạy cảm — phải chủ động minh bạch','[{"key":"Nguyên nhân","value":"Rà soát pháp lý đất & nghĩa vụ tài chính (cần hồ sơ chi tiết)"},{"key":"Hệ quả","value":"Dừng bán + dừng thi công ~5–6 năm"},{"key":"Tác động CĐT","value":"Áp lực tài chính & uy tín giai đoạn 2018–2023"}]'::jsonb,null,'Khoảng lặng dài nhất của dự án. Với khách hàng, đây là rủi ro cảm nhận lớn nhất; với sales, đây là phần bắt buộc phải nắm chắc kịch bản trả lời. Khung trả lời 3 bước: (1) thừa nhận sự kiện có thật; (2) giải thích bản chất là rà soát pháp lý đất giai đoạn siết toàn thị trường, không phải riêng dự án; (3) chốt bằng cột mốc tái cấp phép 2024 + hồ sơ hiện tại. Tuyệt đối không bịa chi tiết khi chưa có văn bản.',6),
  ('c50628d2-93db-5d8a-8df8-87c30c0195ba','00000000-0000-0000-0000-00000000b004','gpxd-2024','Tái khởi động 2024','legal','Cột mốc pháp lý quan trọng nhất','[{"key":"Giấy phép xây dựng","value":"Được cấp lại ~Q2/2024 (cần đối chiếu số văn bản)"},{"key":"Thi công","value":"Tái khởi công trong 2024"},{"key":"Relaunch thương mại","value":"Ra mắt tên mới The Privé (2025)"},{"key":"Ý nghĩa","value":"Điều kiện tiên quyết để quay lại thị trường"}]'::jsonb,'"Năm 2018 dự án bán trước khi mọi thứ hoàn chỉnh. Năm 2024–2025 thì ngược lại: giấy phép có trong tay rồi mới mở bán. Cùng một dự án, nhưng trình tự đã đổi hoàn toàn."','Năm 2024 đánh dấu bước ngoặt: dự án được tái cấp giấy phép xây dựng và tái khởi công — nền tảng để Đất Xanh relaunch dưới tên The Privé trong 2025. Điểm khác biệt với 2018: lần này trình tự là pháp lý trước — bán hàng sau. Sales cần xin bản chụp GPXD và các văn bản kèm theo từ CĐT để dùng làm bằng chứng cứng khi tư vấn.',7),
  ('c32c7b1d-b141-566c-a8ee-90fc4abb3db6','00000000-0000-0000-0000-00000000b004','legal-status','Hồ sơ pháp lý hiện tại','legal','⚠ Cần data room CĐT — chưa khóa từ nguồn public','[{"key":"Quy hoạch 1/500","value":"Cần văn bản phê duyệt"},{"key":"GPXD","value":"Cần bản chụp giấy phép hiện hành"},{"key":"Đủ điều kiện bán","value":"Cần văn bản Sở Xây dựng theo đợt"},{"key":"Tiền sử dụng đất","value":"Cần xác nhận hoàn tất nghĩa vụ"},{"key":"Sổ hồng","value":"Theo tiến độ bàn giao"}]'::jsonb,'"Em không nói suông pháp lý đầy đủ — em gửi Anh/Chị đúng văn bản nào đã có, văn bản nào đang chờ. Mua dự án từng có lịch sử thì minh bạch giấy tờ là cách duy nhất."','Đây là node kiểm soát rủi ro số 1. Ở vòng nghiên cứu public, bộ hồ sơ chi tiết chưa khóa được ở mức đủ tin cậy — vì vậy mọi phát ngôn pháp lý phải dẫn từ văn bản trong data room CĐT hoặc xác nhận của Sở Xây dựng TP.HCM, không dẫn từ tin môi giới. Nơi lấy: chủ đầu tư / microsite chính thức → Sở Xây dựng TP.HCM → UBND địa phương (hồ sơ 1/500).',8),
  ('c5f58a1d-db5a-5103-be31-5bba18bafbaa','00000000-0000-0000-0000-00000000b004','construction','Tiến độ thi công & bàn giao','legal','⚠ Cần ảnh hiện trường + timeline CĐT cập nhật','[{"key":"Tái khởi công","value":"2024"},{"key":"Hiện trạng","value":"Cần cập nhật ảnh công trường theo tháng"},{"key":"Bàn giao dự kiến","value":"2027–2028 (chưa khóa)"},{"key":"Nhà thầu / giám sát","value":"Cần công bố chính thức"}]'::jsonb,null,'Với một dự án từng dừng 5–6 năm, tiến độ thật ngoài công trường là KPI niềm tin quan trọng nhất — hơn cả quảng cáo. Khuyến nghị vận hành: lưu album ảnh tiến độ theo tháng, mốc cất nóc từng block, và chỉ cam kết thời điểm bàn giao theo văn bản CĐT.',9),
  ('9e3344f1-7e19-5e83-85a1-36acaa1099d7','00000000-0000-0000-0000-00000000b004','product-mix','Cơ cấu sản phẩm','product','⚠ Chờ product matrix chính thức theo đợt','[{"key":"Loại hình","value":"Căn hộ cao tầng ven sông"},{"key":"Dòng sản phẩm","value":"1–3PN, duplex, penthouse (theo công bố giai đoạn đầu)"},{"key":"Diện tích tham khảo","value":"~50–120 m² (cần bảng chi tiết)"},{"key":"Thiết kế","value":"Phong cách resort ven sông, tối ưu view sông"}]'::jsonb,null,'Cơ cấu chủ đạo là căn hộ 1–3PN cùng dòng duplex/penthouse tầng cao. Với 3 mặt giáp sông, tỷ lệ căn có view nước là tham số bán hàng then chốt — cần lấy stacking plan chính thức để xác định block/trục căn view sông trực diện trước khi tư vấn vị trí.',10),
  ('548d2a5e-30aa-5dce-93cc-cc45b3133911','00000000-0000-0000-0000-00000000b004','pricing','Giá bán & vùng giá','product','⚠ Time-sensitive — chỉ quote theo price sheet hiệu lực','[{"key":"Giá The Privé","value":"Chưa khóa public — cần bảng giá CĐT theo đợt"},{"key":"Vùng giá truyền thông","value":"~100–130 triệu/m² (tham khảo, chưa xác minh)"},{"key":"Benchmark sơ cấp An Phú","value":"Tham chiếu Eaton Park các đợt gần (cần số mới)"},{"key":"Benchmark toàn TP.HCM","value":"~80 triệu/m² bình quân 2025 (+5,6%)"}]'::jsonb,'"Em chỉ báo giá theo bảng giá có chữ ký và ngày hiệu lực của chủ đầu tư. Giá đồn trên mạng có thể làm Anh/Chị kỳ vọng sai cả tỷ đồng — theo cả hai hướng."','Nguyên tắc sắt: giá chỉ được quote từ bảng giá có hiệu lực của CĐT, kèm ngày phát hành. Vùng giá xuất hiện trên truyền thông (~100–130 triệu/m²) chỉ dùng để định khung kỳ vọng, không dùng để chốt khách. Logic định vị: The Privé nằm giữa hai mỏ neo — benchmark bình quân toàn TP.HCM (~80 triệu/m²) ở dưới và mặt bằng sơ cấp hạng sang An Phú/Thủ Thiêm ở trên. Vị trí ven sông + flagship cho phép neo về phía trên của khung An Phú.',11),
  ('e717c19b-06b3-5f37-8596-97e4b3c52983','00000000-0000-0000-0000-00000000b004','payment','Chính sách thanh toán','product','⚠ Unspecified — cần policy pack theo đợt mở bán','[{"key":"Lịch thanh toán","value":"Cần văn bản theo đợt"},{"key":"Ân hạn gốc/lãi","value":"Cần xác nhận"},{"key":"Ngân hàng tài trợ","value":"Cần danh sách chính thức"},{"key":"Chiết khấu / quà tặng","value":"Cần policy hiệu lực"}]'::jsonb,null,'Chính sách bán hàng của các dự án relaunch thường mạnh tay ở các đợt đầu (kéo dài lịch thanh toán, ân hạn lãi) để tái tạo niềm tin. Mỗi đợt cần lưu policy pack riêng kèm ngày hiệu lực — đây là dữ liệu thay đổi nhanh nhất trong toàn bộ map.',12),
  ('2044a6e5-bd63-59ad-92c1-d2cc05b5db49','00000000-0000-0000-0000-00000000b004','target-customer','Khách hàng mục tiêu','product',null,'[{"key":"Nhóm 1","value":"Cư dân khu Đông nâng cấp chỗ ở (end-user)"},{"key":"Nhóm 2","value":"Nhà đầu tư tích sản theo hạ tầng An Phú"},{"key":"Nhóm 3","value":"Đầu tư cho thuê chuyên gia (gần Thảo Điền/An Phú)"},{"key":"Nhóm 4","value":"Khách cũ Gem Riverside quay lại"}]'::jsonb,null,'Bốn nhóm cầu rõ rệt. Nhóm 3 đáng chú ý: An Phú – Thảo Điền là vùng cầu thuê expat mạnh nhất TP.HCM, căn view sông 2PN là sản phẩm cho thuê "chuẩn khẩu vị" của nhóm chuyên gia nước ngoài. Nhóm 4 cần kịch bản riêng: họ hiểu dự án sâu, nhạy cảm pháp lý — nhưng nếu chốt được, họ chính là người chứng thực mạnh nhất cho dự án.',13),
  ('af96d00f-41d1-5c1a-9f3a-0f6146cbe27a','00000000-0000-0000-0000-00000000b004','hcm-benchmark','Benchmark giá TP.HCM 2025','product',null,'[{"key":"Giá bình quân căn hộ","value":"~80 triệu đồng/m² (2025)"},{"key":"Tăng trưởng","value":"+5,6% so với năm trước"},{"key":"Lưu ý","value":"Macro reference — KHÔNG phải giá dự án"}]'::jsonb,null,'Mốc neo vĩ mô cho mọi cuộc tư vấn: căn hộ các đô thị lớn (gồm TP.HCM) bình quân khoảng 80 triệu/m² năm 2025. Node này được gắn cờ macro reference only — dùng để giải thích mặt bằng, tuyệt đối không trình bày như giá The Privé.',14),
  ('4378d19e-e40c-571f-a347-86f92909fa51','00000000-0000-0000-0000-00000000b004','metro-1','Metro Line 1','metro',null,'[{"key":"Tuyến","value":"Bến Thành – Suối Tiên"},{"key":"Vận hành","value":"22/12/2024"},{"key":"Ý nghĩa","value":"Driver hạ tầng ĐÃ THẬT, không còn là lời hứa"}]'::jsonb,'"Suốt 15 năm khu Đông bán bằng lời hứa metro. Bây giờ metro đã chạy thật mỗi ngày — Anh/Chị đang mua sau khi rủi ro lớn nhất đã được gỡ."','Metro số 1 vận hành từ 22/12/2024 — biến khu Đông từ "vùng hứa hẹn metro" thành vùng đã có metro chạy thật. Đây là khác biệt thế hệ so với mọi chu kỳ bán hàng trước của khu vực.',15),
  ('30448a45-a5af-5d27-b39a-518c24249e8a','00000000-0000-0000-0000-00000000b004','rach-chiec-station','Ga Rạch Chiếc','metro',null,'[{"key":"Vị trí","value":"Khu An Phú, TP Thủ Đức"},{"key":"Mở cửa","value":"22/12/2024"},{"key":"Khoảng cách tới dự án","value":"Ước tính vài phút xe — cần đo GIS sau khi khóa địa chỉ"}]'::jsonb,null,'Ga metro gần cụm An Phú — điểm chạm metro thực tế nhất của cư dân The Privé. Khoảng cách chính xác cần đo lại bằng bản đồ sau khi khóa địa chỉ pháp lý, tránh nói "cách ga X phút" khi chưa có số đo.',16),
  ('2ada0895-903d-5181-94ad-03d968cd91ad','00000000-0000-0000-0000-00000000b004','metro-2-thuthiem','Ga Thủ Thiêm / Metro tương lai','metro','Hạ tầng TƯƠNG LAI — không bán như hiện hữu','[{"key":"Trạng thái","value":"Quy hoạch / chuẩn bị đầu tư"},{"key":"Vai trò","value":"Upside kết nối cụm An Phú – Mai Chí Thọ"},{"key":"Nguyên tắc tư vấn","value":"Trình bày là kỳ vọng tương lai, có mốc nguồn"}]'::jsonb,null,'Cụm ga Thủ Thiêm và các tuyến metro tiếp theo là lớp upside tương lai của khu An Phú. Giá trị tư vấn nằm ở chỗ trình bày đúng trạng thái: đây là quy hoạch — tạo dư địa tăng giá dài hạn, nhưng không được mô tả như tiện ích hiện hữu.',17),
  ('a4ad1154-8ac2-5a52-b755-c342c97e250c','00000000-0000-0000-0000-00000000b004','tt-lt-rail','Đường sắt Thủ Thiêm – Long Thành','metro','Quy hoạch kết nối sân bay','[{"key":"Điểm đầu","value":"Thủ Thiêm"},{"key":"Điểm cuối","value":"Sân bay Long Thành"},{"key":"Trạng thái","value":"Quy hoạch / chuẩn bị đầu tư (cần mốc mới nhất)"}]'::jsonb,null,'Tuyến đường sắt nối CBD mới Thủ Thiêm với sân bay Long Thành — khi triển khai sẽ đưa cụm An Phú vào hành lang "ga đô thị – sân bay quốc tế". Theo dõi mốc phê duyệt để cập nhật node này.',18),
  ('711731c6-431a-55ff-bfa3-456f903761f9','00000000-0000-0000-0000-00000000b004','song-hanh','Đường Song Hành cao tốc','road',null,'[{"key":"Vai trò","value":"Mặt tiền tiếp cận trực tiếp của dự án"},{"key":"Kết nối","value":"Mai Chí Thọ ↔ Đỗ Xuân Hợp dọc cao tốc"},{"key":"Lợi thế","value":"Vào/ra cao tốc và trung tâm không phụ thuộc một trục duy nhất"}]'::jsonb,null,'Trục Song Hành chạy dọc cao tốc Long Thành đoạn qua An Phú — chính là mặt tiền tiếp cận của The Privé. Giá trị thực dụng: tách dòng xe nội khu khỏi cao tốc, cho cư dân nhiều phương án di chuyển về Mai Chí Thọ, Thủ Thiêm và trung tâm.',19),
  ('d368873d-813e-5c4e-b572-1a265d96a143','00000000-0000-0000-0000-00000000b004','an-phu-interchange','Nút giao An Phú (3 tầng)','road','Cửa ngõ hạ tầng sát dự án','[{"key":"Khởi công","value":"12/2022"},{"key":"Quy mô","value":"Hầm chui + cầu vượt, nút giao 3 tầng"},{"key":"Tiến độ","value":"Hoàn thành theo từng hạng mục 2025–2026 (cần mốc cập nhật)"},{"key":"Tác động","value":"Giải tỏa điểm nghẽn lớn nhất cửa ngõ khu Đông"}]'::jsonb,'"Điểm kẹt xe Anh/Chị từng ngán nhất ở An Phú chính là nơi thành phố đang đổ tiền nhiều nhất để gỡ. Mua trước khi nút giao hoàn thiện là mua trước một cú nâng hạ tầng ngay cửa nhà."','Nút giao 3 tầng lớn nhất cửa ngõ phía Đông — nơi giao cắt Mai Chí Thọ, Lương Định Của và đầu cao tốc Long Thành. Mỗi hạng mục thông xe đều cải thiện trực tiếp trải nghiệm ra/vào khu An Phú, tức tác động thẳng vào giá trị sử dụng của The Privé.',20),
  ('c29a40fc-14ad-5dc7-80c6-9599faad514f','00000000-0000-0000-0000-00000000b004','lt-dg-expressway','Cao tốc HCM – Long Thành – Dầu Giây','road',null,'[{"key":"Vai trò","value":"Trục huyết mạch về sân bay Long Thành & Đông Nam Bộ"},{"key":"Kế hoạch","value":"Mở rộng đoạn TP.HCM – Long Thành (cần mốc triển khai mới)"},{"key":"Vị trí dự án","value":"Nằm ngay trục Song Hành của cao tốc"}]'::jsonb,null,'Tuyến cao tốc mà The Privé "tựa lưng" — kết nối thẳng sân bay Long Thành. Kế hoạch mở rộng đoạn TP.HCM – Long Thành khi triển khai sẽ tăng dung lượng trục này; cập nhật mốc chính thức trước khi dùng làm luận điểm thời gian di chuyển.',21),
  ('0fcede5b-9700-528d-8c40-41b2fad00660','00000000-0000-0000-0000-00000000b004','mai-chi-tho','Đại lộ Mai Chí Thọ','road',null,'[{"key":"Vai trò","value":"Trục chính An Phú → Thủ Thiêm → Q1 (hầm sông Sài Gòn)"},{"key":"Ghi chú","value":"Trục đặt các dự án hạng sang: Eaton Park, Global City kế cận"}]'::jsonb,null,'Đại lộ xương sống nối An Phú với Thủ Thiêm và trung tâm Q1 qua hầm vượt sông. Đây cũng là "phố dự án hạng sang" của khu Đông — mặt bằng giá dọc trục này là tham chiếu trực tiếp cho The Privé.',22),
  ('b3ef7ed3-251a-5c55-b418-f2709b22a20c','00000000-0000-0000-0000-00000000b004','ring-road-3','Vành đai 3','road',null,'[{"key":"Trạng thái","value":"Đang thi công, thông xe theo đoạn (cần mốc mới)"},{"key":"Vai trò","value":"Kết nối liên vùng TP.HCM – Đồng Nai – Bình Dương – Long An"}]'::jsonb,null,'Vành đai 3 tái phân bổ dòng xe liên vùng ra khỏi nội đô, cộng hưởng với cao tốc Long Thành — củng cố vị thế "tâm kết nối" của TP Thủ Đức trong dài hạn.',23),
  ('6cb16073-c17d-57df-b05e-90bd1e711789','00000000-0000-0000-0000-00000000b004','luong-dinh-cua','Lương Định Của mở rộng','road',null,'[{"key":"Vai trò","value":"Trục nội khu An Phú – Thủ Thiêm"},{"key":"Tiến độ","value":"Hoàn thiện theo đoạn (cần cập nhật)"}]'::jsonb,null,'Trục nội khu quan trọng nối An Phú với Thủ Thiêm. Việc hoàn thiện các đoạn còn lại sẽ rút ngắn di chuyển hằng ngày của cư dân khu vực — theo dõi cùng tiến độ nút giao An Phú.',24),
  ('97747380-157c-53aa-be84-995641ae7f4c','00000000-0000-0000-0000-00000000b004','long-thanh','Sân bay Long Thành','amenity',null,'[{"key":"Khai thác kỹ thuật","value":"Cuối 2025"},{"key":"Thương mại","value":"Dự kiến trong 2026"},{"key":"Kết nối từ dự án","value":"Trực tiếp qua cao tốc Long Thành"}]'::jsonb,'"Khi Long Thành vận hành thương mại, trục cao tốc này thành hành lang sân bay quốc gia — và The Privé đứng ngay đầu hành lang đó phía TP.HCM."','Sân bay quốc tế lớn nhất Việt Nam bước vào giai đoạn vận hành — và The Privé nằm ngay trục cao tốc dẫn thẳng tới đó. Đây là driver liên vùng nâng tầm cả khu Đông, đặc biệt các vị trí "bám cao tốc" như An Phú.',25),
  ('4584e485-203f-5dfb-9c17-e6e856400f5c','00000000-0000-0000-0000-00000000b004','rach-chiec-sports','Khu liên hợp TT Rạch Chiếc','amenity',null,'[{"key":"Cột mốc","value":"Động thổ đầu 2026"},{"key":"Vai trò","value":"Future urban uplift cho cụm Rạch Chiếc – An Phú"}]'::jsonb,null,'Khu liên hợp thể thao Rạch Chiếc được tái kích hoạt với mốc động thổ đầu 2026 — bổ sung một cực tiện ích quy mô lớn cho cụm An Phú/Rạch Chiếc trong trung hạn. Trình bày đúng trạng thái: đã động thổ, chưa hiện hữu.',26),
  ('d48424ac-c9c1-5b5a-b454-cb6d84a29028','00000000-0000-0000-0000-00000000b004','giong-ong-to','Sông Giồng Ông Tố','amenity',null,'[{"key":"Quan hệ với dự án","value":"3 mặt giáp sông"},{"key":"Giá trị","value":"View nước + khoảng thoáng vĩnh viễn, không bị xây chắn"},{"key":"Tính khan hiếm","value":"Quỹ đất ven sông An Phú gần như cạn"}]'::jsonb,'"Tiện ích có thể xây thêm, nhưng sông thì không. Ba mặt giáp sông giữa An Phú là thứ không dự án nào ra sau có thể copy."','Tài sản tự nhiên không thể sao chép của dự án: 3 mặt được bao bởi sông Giồng Ông Tố. Khác với view nội khu, view sông là khoảng thoáng vĩnh viễn — yếu tố giữ giá mạnh nhất của BĐS cao tầng khi khu vực ngày càng dày đặc.',27),
  ('2eec1ce8-d03c-56ec-849f-9997a5e69437','00000000-0000-0000-0000-00000000b004','amenity-internal','Tiện ích nội khu','amenity','⚠ Chờ legend tiện ích chính thức','[{"key":"Định hướng công bố","value":"Chuỗi tiện ích phong cách resort ven sông"},{"key":"Hạng mục kỳ vọng","value":"Hồ bơi, clubhouse, công viên bờ sông... (cần đối chiếu)"},{"key":"Tài liệu cần lấy","value":"Master legend + mặt bằng tiện ích từng block"}]'::jsonb,null,'Truyền thông dự án định hướng hệ tiện ích resort ven sông, nhưng legend chính thức chưa khóa từ nguồn public. Chỉ tư vấn theo tài liệu CĐT phát hành; tránh liệt kê số lượng tiện ích khi chưa có mặt bằng chính thức.',28),
  ('57afb858-52f3-5d9c-ba6f-7e7272324fc9','00000000-0000-0000-0000-00000000b004','an-phu-amenities','Hub tiện ích An Phú – Thảo Điền','amenity',null,'[{"key":"Thương mại","value":"Vincom Mega Mall Thảo Điền, Estella Place..."},{"key":"Giáo dục","value":"Cụm trường quốc tế dày đặc nhất TP.HCM (BIS, ISHCMC...)"},{"key":"Y tế","value":"Phòng khám/bệnh viện quốc tế khu Thảo Điền – An Phú"},{"key":"Bán kính","value":"~5–10 phút xe (ước tính)"}]'::jsonb,null,'The Privé không cần tự xây hệ sinh thái — nó nằm cạnh hub tiện ích trưởng thành nhất khu Đông: trung tâm thương mại lớn, cụm trường quốc tế và dịch vụ y tế chuẩn expat. Đây là điểm cộng cho cả ở thực lẫn cho thuê.',29),
  ('7febe375-3645-5b30-8d73-82c781a6a605','00000000-0000-0000-0000-00000000b004','an-phu','Phường An Phú','location',null,'[{"key":"Vai trò","value":"Cụm hạng sang trung tâm khu Đông (Q2 cũ)"},{"key":"Mật độ dự án cao cấp","value":"Cao nhất nhì TP Thủ Đức"},{"key":"Đặc điểm","value":"Giao điểm cao tốc – Mai Chí Thọ – metro"}]'::jsonb,null,'An Phú là "địa chỉ vàng" của khu Đông: nơi hội tụ nút giao 3 tầng, trục Mai Chí Thọ, ga metro và mật độ dự án hạng sang dày đặc. Định vị The Privé gắn chặt với thương hiệu khu vực này.',30),
  ('392c1081-009a-5ca3-b838-21d08f7e3ba6','00000000-0000-0000-0000-00000000b004','thu-duc-city','TP Thủ Đức','location',null,'[{"key":"Thành lập","value":"Sáp nhập Q2 + Q9 + Thủ Đức (09/12/2020)"},{"key":"Mô hình","value":"City-in-city đầu tiên của Việt Nam"},{"key":"Quy hoạch","value":"Masterplan 2040 đã được Thủ tướng phê duyệt"}]'::jsonb,null,'Đơn vị hành chính hiện tại của dự án. Mọi giấy tờ, hợp đồng, dữ liệu CRM phải dùng TP Thủ Đức; nhãn "Quận 2" chỉ là lớp thương hiệu thị trường.',31),
  ('721359b3-097b-521b-875f-4e123f8dab12','00000000-0000-0000-0000-00000000b004','q2-legacy','Nhãn "Quận 2" (legacy)','location',null,'[{"key":"Bản chất","value":"Tên gọi quen thuộc của thị trường, không còn là đơn vị hành chính"},{"key":"Ứng dụng","value":"SEO, quảng cáo, ngôn ngữ giao tiếp với khách"},{"key":"Quy tắc","value":"Song song 2 lớp: marketing dùng Q2 — hồ sơ dùng Thủ Đức"}]'::jsonb,null,'Khách vẫn tìm kiếm "căn hộ Quận 2" — vì vậy giữ nhãn Q2 ở lớp marketing là đúng. Nhưng phải tách bạch: mọi văn bản pháp lý ghi TP Thủ Đức. Lệch hai lớp này sẽ làm sai dữ liệu SEO, CRM và cả hợp đồng.',32),
  ('988c4bde-8b7b-5977-a72c-cd12a3f0abea','00000000-0000-0000-0000-00000000b004','thu-thiem','Thủ Thiêm','location',null,'[{"key":"Vai trò","value":"CBD mới của TP.HCM"},{"key":"Khoảng cách từ dự án","value":"~10 phút qua Mai Chí Thọ (ước tính)"},{"key":"Mặt bằng giá","value":"Cao nhất khu Đông (Empire City, Metropole...)"}]'::jsonb,null,'CBD mới — nơi neo trần giá cho toàn khu Đông. The Privé hưởng "hiệu ứng lân cận": ở ngay vành tiếp giáp vùng giá cao nhất nhưng vào ở mức giá An Phú.',33),
  ('bd60f2f3-3e7a-5ef9-97b4-7e62a8a76d98','00000000-0000-0000-0000-00000000b004','thao-dien','Thảo Điền','location',null,'[{"key":"Đặc điểm","value":"Khu cư dân quốc tế (expat) lớn nhất TP.HCM"},{"key":"Ý nghĩa với dự án","value":"Nguồn cầu thuê chất lượng cao kế cận"},{"key":"Kết nối","value":"Liền kề An Phú, có ga Metro 1"}]'::jsonb,null,'Thảo Điền là "mỏ cầu thuê" của khu Đông — cộng đồng chuyên gia nước ngoài đông nhất thành phố. Căn hộ view sông tại An Phú là sản phẩm thay thế tự nhiên khi nguồn cung Thảo Điền khan hiếm và giá thuê leo cao.',34),
  ('9ac6a366-4234-5892-b58a-4a6aa4a92237','00000000-0000-0000-0000-00000000b004','eaton-park','Eaton Park','comparable','Gamuda Land — đối thủ trực tiếp nhất','[{"key":"Chủ đầu tư","value":"Gamuda Land (Malaysia)"},{"key":"Vị trí","value":"Mặt tiền Mai Chí Thọ, An Phú"},{"key":"Quy mô","value":"~6 tháp, ~3.700+ căn (cần đối chiếu)"},{"key":"Mở bán","value":"2024–2025, hấp thụ tốt"},{"key":"Vùng giá tham khảo","value":"~120–140+ triệu/m² các đợt gần (cần số mới)"}]'::jsonb,'"Eaton Park đã chứng minh khách sẵn sàng trả trên 120 triệu/m² cho An Phú không view sông. Câu hỏi cho Anh/Chị: cùng khu đó, thêm 3 mặt sông thì đáng giá bao nhiêu?"','Đối thủ so găng trực tiếp: cùng phân khúc cao cấp, cùng cụm An Phú, mở bán trước và đã thiết lập mặt bằng giá. Điểm khác biệt để The Privé phản công: yếu tố ven sông 3 mặt mà Eaton Park không có, đổi lại Eaton Park có mặt tiền đại lộ và tiến độ bán trước.',35),
  ('4aa17718-70ce-57a6-b879-358d678425f8','00000000-0000-0000-0000-00000000b004','gladia-bythewaters','Gladia by the Waters','comparable','Keppel × Khang Điền — Bình Trưng Đông','[{"key":"Liên doanh","value":"Keppel 49% × Khang Điền 51%"},{"key":"Quy mô","value":"11,8 ha, thấp tầng + cao tầng"},{"key":"Khác biệt","value":"BCA Green Mark for Districts đầu tiên VN"},{"key":"Quan hệ cạnh tranh","value":"Cùng phân khúc tiền, khác loại hình sản phẩm"}]'::jsonb,null,'Cạnh tranh "ví tiền" hơn là cạnh tranh sản phẩm: Gladia mạnh ở compound thấp tầng chuẩn Singapore tại Bình Trưng Đông, The Privé mạnh ở tháp căn hộ ven sông sát hạ tầng An Phú. Khách phân vân giữa hai bên thường đang chọn giữa không gian compound và vị trí trung tâm kết nối.',36),
  ('fe4ca00a-2612-58b3-b11a-71da016b6d75','00000000-0000-0000-0000-00000000b004','lumiere-riverside','Lumière Riverside','comparable','Masterise — benchmark hàng đã bàn giao','[{"key":"Vị trí","value":"Xa lộ Hà Nội, An Phú"},{"key":"Trạng thái","value":"Đã bàn giao, vận hành"},{"key":"Giá thứ cấp tham khảo","value":"~100–120 triệu/m² (cần số mới)"}]'::jsonb,null,'Benchmark quan trọng nhất cho câu hỏi "mua xong thì giá ra sao": hàng hoàn thiện cùng khu An Phú đang giao dịch quanh ngưỡng ba con số. Đây là mỏ neo định giá thứ cấp khi tư vấn The Privé hình thành trong tương lai.',37),
  ('61f0a0ca-864a-5a77-acbf-cd5cc796600b','00000000-0000-0000-0000-00000000b004','global-city','The Global City','comparable','Masterise — 117 ha An Phú','[{"key":"Quy mô","value":"~117 ha, định vị trung tâm mới"},{"key":"Hiện trạng","value":"Low-rise + SOHO đã vận hành, cao tầng theo giai đoạn"},{"key":"Vai trò","value":"Benchmark destination-scale của khu An Phú"}]'::jsonb,null,'Đại đô thị tạo "trọng lực điểm đến" cho cả An Phú — kênh đào nhạc nước, phố thương mại, sự kiện. The Privé hưởng lợi gián tiếp: mọi hoạt động của Global City đều kéo thêm cư dân, dịch vụ và mặt bằng giá cho khu vực xung quanh.',38),
  ('65904915-c1e3-577a-80cd-4e5cb2301e38','00000000-0000-0000-0000-00000000b004','empire-city','Empire City Thủ Thiêm','comparable','Trần giá khu Đông','[{"key":"Vị trí","value":"CBD mới Thủ Thiêm"},{"key":"Quy mô","value":"14,6 ha, tòa landmark 88 tầng"},{"key":"Vùng giá tham khảo","value":"~150–250 triệu/m² (cần số mới)"}]'::jsonb,null,'Mỏ neo trần của thị trường khu Đông. Khoảng cách giá giữa Thủ Thiêm và An Phú chính là "dư địa kể chuyện" của The Privé: cách CBD mới vài phút nhưng giá vẫn ở nấc thấp hơn đáng kể.',39),
  ('dc251210-b545-5069-95ee-eeb0b94f2c92','00000000-0000-0000-0000-00000000b004','estella-heights','Estella Heights','comparable','Bằng chứng tăng giá An Phú','[{"key":"Mở bán","value":"2015 @ ~45 triệu/m²"},{"key":"Hiện tại","value":"~90–110 triệu/m² thứ cấp"},{"key":"Kết quả","value":"Tăng ~2× sau hơn 10 năm"}]'::jsonb,'"An Phú đã từng làm điều này rồi: Estella Heights gấp đôi giá sau một thập kỷ. The Privé đang đứng đúng khu đó, ở đầu một chu kỳ hạ tầng còn lớn hơn."','Case study lịch sử mạnh nhất của An Phú: mua sơ cấp 2015 ở 45 triệu/m², nay giao dịch quanh 100 triệu/m². Dùng để chứng minh quỹ đạo giá của chính khu vực này thay vì hứa hẹn suông.',40),
  ('21abf9a9-b3f4-5b42-9af6-198898e1820d','00000000-0000-0000-0000-00000000b004','diamond-island','Diamond Island','comparable','Benchmark ven sông đã vận hành','[{"key":"Đặc điểm","value":"Căn hộ đảo ven sông, đã vận hành nhiều năm"},{"key":"Vùng giá tham khảo","value":"~100–140 triệu/m² thứ cấp (cần số mới)"},{"key":"Ý nghĩa","value":"Chứng minh premium bền của yếu tố ven sông"}]'::jsonb,null,'Bằng chứng sống cho luận điểm "ven sông giữ giá": sản phẩm đảo/ven sông khu Đông luôn neo trên mặt bằng chung dù tuổi đời đã lớn. Đây là tham chiếu trực tiếp cho premium view sông của The Privé.',41),
  ('a25b08d8-24df-58ca-a88b-eef410d6e74e','00000000-0000-0000-0000-00000000b004','thu-duc-masterplan','Masterplan TP Thủ Đức 2040','policy',null,'[{"key":"Phê duyệt","value":"21/01/2025 — Quyết định 202/QĐ-TTg"},{"key":"Tầm nhìn","value":"2040, định hướng 2050"},{"key":"Quy mô gọi vốn","value":"535 dự án, ~31,6 tỷ USD"}]'::jsonb,null,'Quy hoạch chung TP Thủ Đức đã được Thủ tướng phê duyệt — khung pháp lý dài hạn bảo chứng cho câu chuyện đầu tư hạ tầng của toàn khu Đông, trong đó cụm An Phú là một trong những tâm phát triển.',42),
  ('05159654-79da-58a6-bef7-b41e179cf3f6','00000000-0000-0000-0000-00000000b004','land-price-2026','Bảng giá đất mới 1/1/2026','policy',null,'[{"key":"Hiệu lực","value":"01/01/2026"},{"key":"Mức tăng","value":"Lên tới ~8× bảng giá cũ"},{"key":"Tác động","value":"Reset tham chiếu định giá toàn thị trường"}]'::jsonb,null,'Bảng giá đất mới của TP.HCM nâng mạnh tham chiếu định giá. Hai mặt: chi phí đất đầu vào của dự án mới tăng (hạn chế nguồn cung giá rẻ tương lai) — đồng thời củng cố mặt bằng giá của các dự án đã hoàn tất nghĩa vụ tài chính như The Privé.',43),
  ('98b4c590-65ad-5b92-8910-2f1bb85a8dd1','00000000-0000-0000-0000-00000000b004','risk-control','Khung kiểm soát rủi ro tư vấn','policy','Bắt buộc với mọi sale trước khi gặp khách','[{"key":"Rủi ro 1","value":"Pháp lý: chỉ phát ngôn theo văn bản — không nói \"đầy đủ\" suông"},{"key":"Rủi ro 2","value":"Giá: chỉ quote price sheet hiệu lực, ghi ngày phát hành"},{"key":"Rủi ro 3","value":"Địa lý: marketing dùng \"Q2\", hồ sơ dùng \"TP Thủ Đức\""},{"key":"Rủi ro 4","value":"Lịch sử: chủ động kể Gem Riverside, không để khách phát hiện trước"}]'::jsonb,'"Với dự án từng dừng vì pháp lý, người bán hàng nói đúng sự thật là người bán được nhiều nhất — vì khách đến đây đều đã đọc đủ tin xấu trên mạng."','Bốn quy tắc sắt cho dự án có lịch sử đặc biệt như The Privé. Nguyên lý chung: điều gì chưa có văn bản thì trình bày là "đang chờ xác nhận" — uy tín của sale trong dự án này chính là sản phẩm.',44),
  ('9e87c8c5-cbc8-52cd-8f5e-1c6118d35d56','00000000-0000-0000-0000-00000000b004','data-sources','Tầng nguồn dữ liệu ưu tiên','policy',null,'[{"key":"Tầng 1","value":"CĐT / microsite chính thức / thông cáo BLUEMARQ"},{"key":"Tầng 2","value":"Sở Xây dựng TP.HCM (văn bản đủ điều kiện bán)"},{"key":"Tầng 3","value":"UBND / hồ sơ quy hoạch 1/500"},{"key":"Tầng 4","value":"Báo lớn (VnExpress, CafeF...) — đối chiếu chéo"},{"key":"Tầng 5","value":"Portal môi giới — CHỈ để benchmark, luôn gắn cờ secondary"}]'::jsonb,null,'Trật tự nguồn khi cập nhật bất kỳ node nào trong map. Nguyên tắc: dữ liệu pháp lý và giá chỉ được khóa từ Tầng 1–2; tin portal môi giới không bao giờ được dùng làm căn cứ phát ngôn với khách.',45);
